class AllOne {
    Map<String, Integer> map = new HashMap<>();

    public AllOne() {
    }

    public void inc(String key) {
        if (!map.containsKey(key)) {
            map.put(key, 1);
        } else {
            int count = map.get(key);
            map.put(key, count + 1);
        }
    }

    public void dec(String key) {
        if (!map.containsKey(key)) {
            throw new RuntimeException("Key not found");
        }
        int count = map.get(key);
        if (count == 1) {
            map.remove(key);
        } else {
            map.put(key, count - 1);
        }
    }

    public String getMaxKey() {
        return Collections.max(map.keySet(), Collections.reverseOrder()).toString();
    }

    public String getMinKey() {
        return Collections.min(map.keySet(), Collections.reverseOrder()).toString();
    }
}
